            //             "fee": "0.00301420496",
            //             "fee_currency": "USDT",
            //             "point_fee": "0",
            //             "gt_fee": "0"
            //         }
            //     ]
            //
            // perpetual swap
            //
            //     [
            //         {
            //             "size": -5,
            //             "order_id": "130264979823",
            //             "id": 26884791,
            //             "role": "taker",
            //             "create_time": 1645465199.5472,
            //             "contract": "DOGE_USDT",
            //             "price": "0.136888"
            //         }
            //     ]
            //
            // future
            //
            //     [
            //         {
            //             "id": 121234231,
            //             "create_time": 1514764800.123,
            //             "contract": "BTC_USDT",
            //             "order_id": "21893289839",
