    public Object parseTrade(Object trade, Object... optionalArgs)
    {
        //
        // public
        //
        //  spot:
        //     {
        //         "id": "1334253759",
        //         "create_time": "1626342738",
        //         "create_time_ms": "1626342738331.497000",
        //         "currency_pair": "BTC_USDT",
        //         "side": "sell",
        //         "amount": "0.0022",
        //         "price": "32452.16"
        //     }
        //
        //  swap:
        //
        //    {
        //        "id": "442288327",
        //        "contract": "BTC_USDT",
        //        "create_time": "1739814676.707",
        //        "create_time_ms": "1739814676.707",
        //        "size": "-105",
        //        "price": "95594.8"
        //    }
        //
        //
        // public ws
        //
        //     {
        //         "id": 221994511,
        //         "time": 1580311438.618647,
        //         "price": "9309",
        //         "amount": "0.0019",
        //         "type": "sell"
        //     }
        //
        // spot rest
        //
        //     {
        //         "id": "2876130500",
        //         "create_time": "1645464610",
        //         "create_time_ms": "1645464610777.399200",
        //         "currency_pair": "DOGE_USDT",
        //         "side": "sell",
        //         "role": "taker",
        //         "amount": "10.97",
        //         "price": "0.137384",
        //         "order_id": "125924049993",
        //         "fee": "0.00301420496",
        //         "fee_currency": "USDT",
        //         "point_fee": "1.1",
        //         "gt_fee":"2.2"
        //     }
        //
        // perpetual swap rest
        //
        //     {
        //         "size": -5,
        //         "order_id": "130264979823",
        //         "id": 26884791,
        //         "role": "taker",
        //         "create_time": 1645465199.5472,
        //         "contract": "DOGE_USDT",
        //         "price": "0.136888"
        //     }
        //
        // future rest
        //
        //     {
        //         "id": 121234231,
        //         "create_time": 1514764800.123,
        //         "contract": "BTC_USDT",
        //         "order_id": "21893289839",
        //         "size": 100,
        //         "price": "100.123",
        //         "role": "taker"
        //     }
        //
        // fetchTrades: option
        //
        //     {
        //         "size": -5,
        //         "id": 25,
        //         "create_time": 1682378573,
        //         "contract": "ETH_USDT-20230526-2000-P",
        //         "price": "209.1"
        //     }
        //
        // fetchMyTrades: option
        //
        //     {
        //         "underlying_price": "26817.84",
        //         "size": -1,
        //         "contract": "BTC_USDT-20230602-26500-C",
        //         "id": 16,
        //         "role": "taker",
        //         "create_time": 1685594770,
        //         "order_id": 2611026125,
        //         "price": "333"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object id = this.safeString2(trade, "id", "trade_id");
        Object timestamp = null;
        Object msString = this.safeString(trade, "create_time_ms");
        if (Helpers.isTrue(!Helpers.isEqual(msString, null)))
        {
            msString = Precise.stringMul(msString, "1000");
            msString = Helpers.slice(((String)msString), 0, 13);
            timestamp = this.parseToInt(msString);
        } else
        {
            timestamp = this.safeTimestamp2(trade, "time", "create_time");
        }
        Object marketId = this.safeString2(trade, "currency_pair", "contract");
        Object marketType = ((Helpers.isTrue((Helpers.inOp(trade, "contract"))))) ? "contract" : "spot";
        market = this.safeMarket(marketId, market, "_", marketType);
        Object amountString = this.safeString2(trade, "amount", "size");
        Object priceString = this.safeString(trade, "price");
        Object contractSide = ((Helpers.isTrue(Precise.stringLt(amountString, "0")))) ? "sell" : "buy";
        amountString = Precise.stringAbs(amountString);
        Object side = this.safeString2(trade, "side", "type", contractSide);
        Object orderId = this.safeString(trade, "order_id");
        Object feeAmount = this.safeString(trade, "fee");
        Object gtFee = this.omitZero(((String)this.safeString(trade, "gt_fee")));
        Object pointFee = this.omitZero(((String)this.safeString(trade, "point_fee")));
        Object fees = new java.util.ArrayList<Object>(java.util.Arrays.asList());
        if (Helpers.isTrue(!Helpers.isEqual(feeAmount, null)))
        {
            Object feeCurrencyId = this.safeString(trade, "fee_currency");
            Object feeCurrencyCode = this.safeCurrencyCode(feeCurrencyId);
            if (Helpers.isTrue(Helpers.isEqual(feeCurrencyCode, null)))
            {
                feeCurrencyCode = this.safeString(market, "settle");
            }
final Object finalFeeAmount = feeAmount;
            final Object finalFeeCurrencyCode = feeCurrencyCode;
                        ((java.util.List<Object>)fees).add(new java.util.HashMap<String, Object>() {{
                put( "cost", finalFeeAmount );
                put( "currency", finalFeeCurrencyCode );
            }});
        }
        if (Helpers.isTrue(!Helpers.isEqual(gtFee, null)))
        {
final Object finalGtFee = gtFee;
                        ((java.util.List<Object>)fees).add(new java.util.HashMap<String, Object>() {{
                put( "cost", finalGtFee );
                put( "currency", "GT" );
            }});
        }
        if (Helpers.isTrue(!Helpers.isEqual(pointFee, null)))
        {
final Object finalPointFee = pointFee;
                        ((java.util.List<Object>)fees).add(new java.util.HashMap<String, Object>() {{
                put( "cost", finalPointFee );
                put( "currency", "GATEPOINT" );
            }});
        }
        Object takerOrMaker = this.safeString(trade, "role");
        final Object finalTimestamp = timestamp;
        final Object finalMarket = market;
        final Object finalAmountString = amountString;
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "info", trade );
            put( "id", id );
            put( "timestamp", finalTimestamp );
            put( "datetime", GateCore.this.iso8601(finalTimestamp) );
            put( "symbol", Helpers.GetValue(finalMarket, "symbol") );
            put( "order", orderId );
            put( "type", null );
            put( "side", side );
            put( "takerOrMaker", takerOrMaker );
            put( "price", priceString );
            put( "amount", finalAmountString );
            put( "cost", null );
            put( "fee", null );
            put( "fees", fees );
        }}, market);
    }

