    /**
     * @method
     * @name gate#fetchLiquidations
     * @description retrieves the public liquidations of a trading pair
     * @see https://www.gate.com/docs/developers/apiv4/en/#query-liquidation-order-history
     * @param {string} symbol unified CCXT market symbol
     * @param {int} [since] the earliest time in ms to fetch liquidations for
     * @param {int} [limit] the maximum number of liquidation structures to retrieve
     * @param {object} [params] exchange specific parameters for the exchange API endpoint
     * @param {int} [params.until] timestamp in ms of the latest liquidation
     * @returns {object} an array of [liquidation structures]{@link https://docs.ccxt.com/?id=liquidation-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchLiquidations(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object since = Helpers.getArg(optionalArgs, 0, null);
            Object limit = Helpers.getArg(optionalArgs, 1, null);
            Object parameters = Helpers.getArg(optionalArgs, 2, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object market = this.market(symbol);
            if (!Helpers.isTrue(Helpers.GetValue(market, "swap")))
            {
                throw new NotSupported((String)Helpers.add(this.id, " fetchLiquidations() supports swap markets only")) ;
            }
            Object request = new java.util.HashMap<String, Object>() {{
                put( "settle", Helpers.GetValue(market, "settleId") );
                put( "contract", Helpers.GetValue(market, "id") );
            }};
            if (Helpers.isTrue(!Helpers.isEqual(since, null)))
            {
                Helpers.addElementToObject(request, "from", since);
            }
            if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
            {
                Helpers.addElementToObject(request, "limit", limit);
            }
            var requestparametersVariable = this.handleUntilOption("to", request, parameters);
            request = ((java.util.List<Object>) requestparametersVariable).get(0);
            parameters = ((java.util.List<Object>) requestparametersVariable).get(1);
            Object response = (this.publicFuturesGetSettleLiqOrders(this.extend(request, parameters))).join();
            //
            //     [
            //         {
            //             "contract": "BTC_USDT",
            //             "left": 0,
            //             "size": -165,
            //             "fill_price": "28070",
            //             "order_price": "28225",
            //             "time": 1696736132
            //         },
            //     ]
            //
            return this.parseLiquidations(response, market, since, limit);
        });

    }

    /**
     * @method
     * @name gate#fetchMyLiquidations
     * @description retrieves the users liquidated positions
     * @see https://www.gate.com/docs/developers/apiv4/en/#query-liquidation-history
     * @see https://www.gate.com/docs/developers/apiv4/en/#query-liquidation-history-2
     * @see https://www.gate.com/docs/developers/apiv4/en/#list-user-s-liquidation-history-of-specified-underlying
     * @param {string} symbol unified CCXT market symbol
     * @param {int} [since] the earliest time in ms to fetch liquidations for
     * @param {int} [limit] the maximum number of liquidation structures to retrieve
     * @param {object} [params] exchange specific parameters for the exchange API endpoint
     * @returns {object} an array of [liquidation structures]{@link https://docs.ccxt.com/?id=liquidation-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchMyLiquidations(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbol = Helpers.getArg(optionalArgs, 0, null);
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(symbol, null)))
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " fetchMyLiquidations() requires a symbol argument")) ;
            }
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object market = this.market(symbol);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "contract", Helpers.GetValue(market, "id") );
            }};
            Object response = null;
            if (Helpers.isTrue(Helpers.isTrue((Helpers.GetValue(market, "swap"))) || Helpers.isTrue((Helpers.GetValue(market, "future")))))
            {
                if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
                {
                    Helpers.addElementToObject(request, "limit", limit);
                }
                Helpers.addElementToObject(request, "settle", Helpers.GetValue(market, "settleId"));
            } else if (Helpers.isTrue(Helpers.GetValue(market, "option")))
            {
                Object marketId = Helpers.GetValue(market, "id");
                Object optionParts = Helpers.split(((String)marketId), "-");
                Helpers.addElementToObject(request, "underlying", this.safeString(optionParts, 0));
            }
            if (Helpers.isTrue(Helpers.GetValue(market, "swap")))
            {
                response = (this.privateFuturesGetSettleLiquidates(this.extend(request, parameters))).join();
            } else if (Helpers.isTrue(Helpers.GetValue(market, "future")))
            {
                response = (this.privateDeliveryGetSettleLiquidates(this.extend(request, parameters))).join();
            } else if (Helpers.isTrue(Helpers.GetValue(market, "option")))
            {
                response = (this.privateOptionsGetPositionClose(this.extend(request, parameters))).join();
            } else
            {
                throw new NotSupported((String)Helpers.add(Helpers.add(Helpers.add(this.id, " fetchMyLiquidations() does not support "), Helpers.GetValue(market, "type")), " orders")) ;
            }
            //
            // swap and future
            //
            //     [
            //         {
            //             "time": 1548654951,
            //             "contract": "BTC_USDT",
            //             "size": 600,
            //             "leverage": "25",
            //             "margin": "0.006705256878",
            //             "entry_price": "3536.123",
            //             "liq_price": "3421.54",
            //             "mark_price": "3420.27",
            //             "order_id": 317393847,
            //             "order_price": "3405",
            //             "fill_price": "3424",
            //             "left": 0
            //         }
            //     ]
            //
            // option
            //
            //     [
            //         {
            //             "time": 1631764800,
            //             "pnl": "-42914.291",
            //             "settle_size": "-10001",
            //             "side": "short",
            //             "contract": "BTC_USDT-20210916-5000-C",
            //             "text": "settled"
            //         }
            //     ]
            //
            return this.parseLiquidations(response, market, since, limit);
        });

    }

    public Object parseLiquidation(Object liquidation, Object... optionalArgs)
    {
        //
        // fetchLiquidations
        //
        //     {
        //         "contract": "BTC_USDT",
        //         "left": 0,
        //         "size": -165,
        //         "fill_price": "28070",
        //         "order_price": "28225",
        //         "time": 1696736132
        //     }
        //
        // swap and future: fetchMyLiquidations
        //
        //     {
        //         "time": 1548654951,
        //         "contract": "BTC_USDT",
        //         "size": 600,
        //         "leverage": "25",
        //         "margin": "0.006705256878",
        //         "entry_price": "3536.123",
        //         "liq_price": "3421.54",
        //         "mark_price": "3420.27",
        //         "order_id": 317393847,
        //         "order_price": "3405",
        //         "fill_price": "3424",
        //         "left": 0
        //     }
        //
        // option: fetchMyLiquidations
        //
        //     {
        //         "time": 1631764800,
        //         "pnl": "-42914.291",
        //         "settle_size": "-10001",
        //         "side": "short",
        //         "contract": "BTC_USDT-20210916-5000-C",
        //         "text": "settled"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(liquidation, "contract");
        Object timestamp = this.safeTimestamp(liquidation, "time");
        Object size = this.safeString2(liquidation, "size", "settle_size");
        Object left = this.safeString(liquidation, "left", "0");
        Object contractsString = Precise.stringAbs(Precise.stringSub(size, left));
        Object contractSizeString = this.safeString(market, "contractSize");
        Object priceString = this.safeString2(liquidation, "liq_price", "fill_price");
        Object baseValueString = Precise.stringMul(contractsString, contractSizeString);
        Object quoteValueString = this.safeString(liquidation, "pnl");
        if (Helpers.isTrue(Helpers.isEqual(quoteValueString, null)))
        {
            quoteValueString = Precise.stringMul(baseValueString, priceString);
        }
        // --- derive side ---
        // 1) options payload has explicit 'side': 'long' | 'short'
        Object optPos = this.safeStringLower(liquidation, "side");
        Object side = null;
        if (Helpers.isTrue(Helpers.isEqual(optPos, "long")))
        {
            side = "buy";
        } else if (Helpers.isTrue(Helpers.isEqual(optPos, "short")))
        {
            side = "sell";
        } else
        {
            if (Helpers.isTrue(!Helpers.isEqual(size, null)))
            {
                if (Helpers.isTrue(Precise.stringGt(size, "0")))
                {
                    side = "buy";
                } else if (Helpers.isTrue(Precise.stringLt(size, "0")))
                {
                    side = "sell";
                }
            }
        }
        final Object finalSide = side;
        final Object finalQuoteValueString = quoteValueString;
        return this.safeLiquidation(new java.util.HashMap<String, Object>() {{
            put( "info", liquidation );
            put( "symbol", GateCore.this.safeSymbol(marketId, market) );
            put( "contracts", GateCore.this.parseNumber(contractsString) );
            put( "contractSize", GateCore.this.parseNumber(contractSizeString) );
            put( "price", GateCore.this.parseNumber(priceString) );
            put( "side", finalSide );
            put( "baseValue", GateCore.this.parseNumber(baseValueString) );
            put( "quoteValue", GateCore.this.parseNumber(Precise.stringAbs(finalQuoteValueString)) );
            put( "timestamp", timestamp );
            put( "datetime", GateCore.this.iso8601(timestamp) );
        }});
    }

    /**
     * @method
     * @name gate#fetchGreeks
     * @description fetches an option contracts greeks, financial metrics used to measure the factors that affect the price of an options contract
     * @see https://www.gate.com/docs/developers/apiv4/en/#query-options-market-ticker-information
     * @param {string} symbol unified symbol of the market to fetch greeks for
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a [greeks structure]{@link https://docs.ccxt.com/?id=greeks-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchGreeks(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object market = this.market(symbol);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "underlying", Helpers.GetValue(Helpers.GetValue(market, "info"), "underlying") );
            }};
            Object response = (this.publicOptionsGetTickers(this.extend(request, parameters))).join();
            //
            //     [
            //         {
            //             "vega": "1.78992",
            //             "leverage": "6.2096777055417",
            //             "ask_iv": "0.6245",
            //             "delta": "-0.69397",
            //             "last_price": "0",
            //             "theta": "-2.5723",
            //             "bid1_price": "222.9",
            //             "mark_iv": "0.5909",
            //             "name": "ETH_USDT-20231201-2300-P",
            //             "bid_iv": "0.5065",
            //             "ask1_price": "243.6",
            //             "mark_price": "236.57",
            //             "position_size": 0,
            //             "bid1_size": 368,
            //             "ask1_size": -335,
            //             "gamma": "0.00116"
            //         },
            //     ]
            //
            Object marketId = Helpers.GetValue(market, "id");
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(response)); i++)
            {
                Object entry = Helpers.GetValue(response, i);
                Object entryMarketId = this.safeString(entry, "name");
                if (Helpers.isTrue(Helpers.isEqual(entryMarketId, marketId)))
                {
                    return this.parseGreeks(entry, market);
                }
            }
            return null;
        });

    }

    public Object parseGreeks(Object greeks, Object... optionalArgs)
    {
        //
        //     {
        //         "vega": "1.78992",
        //         "leverage": "6.2096777055417",
        //         "ask_iv": "0.6245",
        //         "delta": "-0.69397",
        //         "last_price": "0",
        //         "theta": "-2.5723",
        //         "bid1_price": "222.9",
        //         "mark_iv": "0.5909",
        //         "name": "ETH_USDT-20231201-2300-P",
        //         "bid_iv": "0.5065",
        //         "ask1_price": "243.6",
        //         "mark_price": "236.57",
        //         "position_size": 0,
        //         "bid1_size": 368,
        //         "ask1_size": -335,
        //         "gamma": "0.00116"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(greeks, "name");
        Object symbol = this.safeSymbol(marketId, market);
        return new java.util.HashMap<String, Object>() {{
            put( "symbol", symbol );
            put( "timestamp", null );
            put( "datetime", null );
            put( "delta", GateCore.this.parseNumber(GateCore.this.safeNumber(greeks, "delta")) );
            put( "gamma", GateCore.this.parseNumber(GateCore.this.safeNumber(greeks, "gamma")) );
            put( "theta", GateCore.this.parseNumber(GateCore.this.safeNumber(greeks, "theta")) );
            put( "vega", GateCore.this.parseNumber(GateCore.this.safeNumber(greeks, "vega")) );
            put( "rho", null );
            put( "bidSize", GateCore.this.parseNumber(GateCore.this.safeNumber(greeks, "bid1_size")) );
            put( "askSize", GateCore.this.parseNumber(GateCore.this.safeNumber(greeks, "ask1_size")) );
            put( "bidImpliedVolatility", GateCore.this.parseNumber(GateCore.this.safeNumber(greeks, "bid_iv")) );
            put( "askImpliedVolatility", GateCore.this.parseNumber(GateCore.this.safeNumber(greeks, "ask_iv")) );
            put( "markImpliedVolatility", GateCore.this.parseNumber(GateCore.this.safeNumber(greeks, "mark_iv")) );
            put( "bidPrice", GateCore.this.parseNumber(GateCore.this.safeNumber(greeks, "bid1_price")) );
            put( "askPrice", GateCore.this.parseNumber(GateCore.this.safeNumber(greeks, "ask1_price")) );
            put( "markPrice", GateCore.this.parseNumber(GateCore.this.safeNumber(greeks, "mark_price")) );
            put( "lastPrice", GateCore.this.parseNumber(GateCore.this.safeNumber(greeks, "last_price")) );
            put( "underlyingPrice", GateCore.this.parseNumber(Helpers.GetValue(Helpers.GetValue(market, "info"), "underlying_price")) );
            put( "info", greeks );
        }};
    }

